const api='/api/v1/mapping-bundles';let bundles=[];const $=id=>document.getElementById(id);const bytes=n=>{if(n<1024)return `${n} B`;if(n<1048576)return `${(n/1024).toFixed(1)} KB`;return `${(n/1048576).toFixed(1)} MB`};async function request(url,options={}){const response=await fetch(url,{headers:{'Content-Type':'application/json',...(options.headers||{})},...options});if(!response.ok){let detail='Request failed';try{const body=await response.json();detail=typeof body.detail==='string'?body.detail:JSON.stringify(body.detail)}catch{}throw new Error(detail)}if(response.status===204)return null;return response.json()}function escapeHtml(v){return String(v).replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]))}function render(){const q=$('search').value.trim().toLowerCase();const visible=bundles.filter(b=>`${b.name} ${b.version} ${b.filename}`.toLowerCase().includes(q));$('bundle-rows').innerHTML=visible.map(b=>`<tr><td><strong>${escapeHtml(b.name)}</strong><small>${escapeHtml(b.filename)}</small></td><td>${escapeHtml(b.version)}</td><td>${b.mapping_count}</td><td>${bytes(b.byte_size)}</td><td>${b.created_at?new Date(b.created_at).toLocaleString():'—'}</td><td><div class="actions"><button data-inspect="${encodeURIComponent(b.filename)}">Inspect</button><a class="action" href="${api}/${encodeURIComponent(b.filename)}/download">Download</a><button class="delete" data-delete="${encodeURIComponent(b.filename)}">Delete</button></div></td></tr>`).join('');$('empty').hidden=visible.length>0;const max=Math.max(1,...visible.map(b=>b.byte_size));$('storage-bars').innerHTML=visible.slice(0,12).map(b=>`<div class="bar" title="${escapeHtml(b.filename)}: ${bytes(b.byte_size)}" style="height:${Math.max(12,Math.round(b.byte_size/max*70))}px"><span>${escapeHtml(b.name.slice(0,9))}</span></div>`).join('');document.querySelectorAll('[data-inspect]').forEach(btn=>btn.onclick=()=>inspect(decodeURIComponent(btn.dataset.inspect)));document.querySelectorAll('[data-delete]').forEach(btn=>btn.onclick=()=>removeBundle(decodeURIComponent(btn.dataset.delete)))}async function load(){try{const data=await request(api);bundles=data.bundles;$('bundle-count').textContent=data.summary.bundle_count;$('total-bytes').textContent=bytes(data.summary.total_bytes);$('mapping-count').textContent=data.summary.mapping_count;render()}catch(error){$('form-message').textContent=error.message}}async function inspect(filename){try{const data=await request(`${api}/${encodeURIComponent(filename)}`);$('manifest').textContent=JSON.stringify(data,null,2);$('inspect-dialog').showModal()}catch(error){alert(error.message)}}async function removeBundle(filename){if(!confirm(`Delete ${filename}?`))return;try{await request(`${api}/${encodeURIComponent(filename)}`,{method:'DELETE'});await load()}catch(error){alert(error.message)}}$('bundle-form').addEventListener('submit',async event=>{event.preventDefault();const message=$('form-message');message.textContent='Creating…';try{const mappings=JSON.parse($('mappings').value);const metadata=JSON.parse($('metadata').value);await request(api,{method:'POST',body:JSON.stringify({name:$('name').value,version:$('version').value,mappings,metadata})});message.textContent='Bundle created.';$('name').value='';await load()}catch(error){message.textContent=error.message}});$('search').addEventListener('input',render);$('close-dialog').onclick=()=>$('inspect-dialog').close();load();